      const {id}=await createProject();const task=agentTask(id,"SUCCESS");const job=await enqueueAgent(repository,task);const claim=await claimIsolatedFixture(repository,job.jobId,`race-worker-${iteration}`,`race-claim-${iteration}`,120_000);const barrier=await admin.connect();
