        const first=completionWins?repository.complete(completionContext(claim!),await agentResult(task,claim!.fencingToken)):repository.requestCancel(job.jobId,`race-cancel-${iteration}`,digest(`race-${iteration}`));
        await waitFor(async()=>Number((await admin.query<{count:string}>("SELECT count(*) count FROM pg_stat_activity WHERE wait_event_type='Lock' AND query LIKE '%background_jobs%FOR UPDATE%' AND pid<>pg_backend_pid()")).rows[0]!.count)>0);
