  it("AT-18 spaetes Runtime-SUCCEEDED wird discarded - AC2 AC6 AC7 AC8",async()=>{const f=await cancellingFixture("at18");await f.repository.complete(completionContext(f.claim),await agentResult(f.task,f.claim.fencingToken));expect(await f.repository.getStatus(f.enqueued.jobId)).toMatchObject({status:"CANCELLING",result:null});expect((await admin.query("SELECT 1 FROM builder.agent_job_late_results WHERE project_id=$1 AND job_id=$2",[f.id,f.enqueued.jobId])).rowCount).toBe(1);});
  it("AT-19 Reclaim fenced alten Worker und alte Evidence - AC1 AC5 AC6 AC8",async()=>{const f=await cancellingFixture("at19");const staleEvidence=evidenceFor(f.claim);await admin.query("UPDATE builder.background_jobs SET lease_expires_at=clock_timestamp()-interval '1 millisecond' WHERE id=$1",[f.enqueued.jobId]);const current=await claimIsolatedFixture(f.repository,f.enqueued.jobId,"at19-current","at19-current-claim",120_000);await expect(f.repository.complete(completionContext(f.claim),await agentResult(f.task,f.claim.fencingToken))).rejects.toBeInstanceOf(AgentJobLeaseLostError);expect(await f.repository.verifyTerminationEvidence(agentGuard(current!),staleEvidence)).toMatchObject({validity:"REJECTED",rejectionReason:"LEASE_GENERATION_MISMATCH"});expect((await admin.query("SELECT count(*)::int count FROM builder.agent_job_audit_events WHERE project_id=$1 AND job_id=$2 AND event_type='EVIDENCE_REJECTED'",[f.id,f.enqueued.jobId])).rows[0]?.count).toBe(1);expect((await admin.query("SELECT count(*)::int count FROM builder.outbox_events WHERE project_id=$1 AND aggregate_id=$2 AND event_type='JobCancelled'",[f.id,f.enqueued.jobId])).rows[0]?.count).toBe(0);});
  it("AT-20 Crash nach Evidence-Verifikation vor Cancellation-Commit - AC3 AC5 AC6 AC8",async()=>{const f=await cancellingFixture("at20",1);const e=evidenceFor(f.claim);expect(await f.repository.verifyTerminationEvidence(agentGuard(f.claim),e)).toMatchObject({validity:"VALID"});await admin.query("UPDATE builder.background_jobs SET lease_expires_at=clock_timestamp()-interval '1 millisecond' WHERE id=$1",[f.enqueued.jobId]);const current=await claimIsolatedFixture(f.repository,f.enqueued.jobId,"at20-recovery","at20-recovery-claim",120_000);expect(await f.repository.verifyTerminationEvidence(agentGuard(current!),e)).toMatchObject({validity:"VALID",idempotentReplay:true});const context=createAgentJobCancellationCompletionContext(current!,e.evidenceId),messageId=deriveAgentJobCompletionId(context);expect(await f.repository.confirmCancelled(context,{schemaVersion:1,projectId:f.id,taskId:f.task.taskId,attemptId:f.task.attemptId,runId:f.task.runId,status:"CANCELLED",findings:[],artifacts:[],decisions:[],errorCode:null})).toMatchObject({status:"CANCELLED"});expect((await admin.query("SELECT count(*)::int count FROM builder.agent_job_audit_events WHERE project_id=$1 AND job_id=$2 AND event_type='EVIDENCE_VERIFIED'",[f.id,f.enqueued.jobId])).rows[0]?.count).toBe(1);expect((await admin.query("SELECT count(*)::int count FROM builder.inbox_events WHERE project_id=$1 AND consumer_identity='agent-job-completion' AND message_id=$2 AND status='PROCESSED'",[f.id,messageId])).rows[0]?.count).toBe(1);expect((await admin.query("SELECT count(*)::int count FROM builder.outbox_events WHERE project_id=$1 AND aggregate_id=$2 AND event_type='JobCancelled'",[f.id,f.enqueued.jobId])).rows[0]?.count).toBe(1);});
  it("AT-21 terminale Monotonie - AC1 AC2 AC6 AC8",async()=>{const f=await cancellingFixture("at21");await acceptFixtureEvidence(f);await expect(f.repository.complete(completionContext(f.claim),await agentResult(f.task,f.claim.fencingToken))).rejects.toBeInstanceOf(AgentJobLeaseLostError);expect(await f.repository.getStatus(f.enqueued.jobId)).toMatchObject({status:"CANCELLED"});});
